import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026/05/25（週一）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-25.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-25.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-25.md"};function h(l,t,i,n,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="🫘-黃豆追蹤日報-—-2026-05-25-週一" tabindex="-1">🫘 黃豆追蹤日報 — 2026/05/25（週一） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-25-週一" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026/05/25（週一）&quot;">​</a></h1><p><strong>查詢時間：05:00 TST（2026-05-24 21:00 UTC）</strong><strong>備註：CME 黃豆期貨 14:00–20:00 ET 休息中，無法取得即時期貨報價。以下引用最新可取得數據。</strong></p><hr><h2 id="🔑-今日最大敘事-美伊停火協議-→-霍爾木茲海峽重開預期-→-大宗商品價格波動" tabindex="-1">🔑 今日最大敘事：美伊停火協議 → 霍爾木茲海峽重開預期 → 大宗商品價格波動 <a class="header-anchor" href="#🔑-今日最大敘事-美伊停火協議-→-霍爾木茲海峽重開預期-→-大宗商品價格波動" aria-label="Permalink to &quot;🔑 今日最大敘事：美伊停火協議 → 霍爾木茲海峽重開預期 → 大宗商品價格波動&quot;">​</a></h2><p>US-Iran MoU 若達成，霍爾木茲海峽通航恢復將大幅降低全球農產品運輸成本與風險溢價。此為黃豆市場的關鍵地緣變數。</p><hr><h2 id="📊-8-項追蹤指標檢查" tabindex="-1">📊 8 項追蹤指標檢查 <a class="header-anchor" href="#📊-8-項追蹤指標檢查" aria-label="Permalink to &quot;📊 8 項追蹤指標檢查&quot;">​</a></h2><h3 id="_1️⃣-usda-種植進度報告-每週" tabindex="-1">1️⃣ USDA 種植進度報告（每週） <a class="header-anchor" href="#_1️⃣-usda-種植進度報告-每週" aria-label="Permalink to &quot;1️⃣ USDA 種植進度報告（每週）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>全國大豆種植</td><td>🔴 有變化</td><td>截至 5/17 週：全國種植率 67%（前年同期 +7pts，五年平均 +7pts）</td></tr><tr><td>苗情 emergence</td><td>🟢 偏樂觀</td><td>32% 已出苗（五年平均 +9pts）</td></tr><tr><td>重點州別</td><td>—</td><td>WI 54%, MI 37%, ND 58%, IN 44%, IL 46%, NE 40%</td></tr><tr><td>趨勢</td><td>🟡 持續關注</td><td>雖然快於五年平均，但落後去年同期 7pts；需留意後續天氣</td></tr></tbody></table><p>📅 <strong>來源</strong>: DTN/PF (2026-05-18), Southeast AgNet (2026-05-20)</p><h3 id="_2️⃣-巴西供應-收割-出口-豐收-每月" tabindex="-1">2️⃣ 巴西供應（收割+出口+豐收）（每月） <a class="header-anchor" href="#_2️⃣-巴西供應-收割-出口-豐收-每月" aria-label="Permalink to &quot;2️⃣ 巴西供應（收割+出口+豐收）（每月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>巴西收成進度</td><td>🟡 資料不足</td><td>巴西 2025/26 作季正在收割期，無最新月度數據</td></tr><tr><td>出口量</td><td>🟡 資料不足</td><td>待下一月 SCOOP / CONAB 報告發布</td></tr></tbody></table><p>⚠️ <strong>下次更新</strong>：CONAB 6 月月度供需報告</p><h3 id="_3️⃣-尿素價格-多單訊號-每月" tabindex="-1">3️⃣ 尿素價格 + 多單訊號（每月） <a class="header-anchor" href="#_3️⃣-尿素價格-多單訊號-每月" aria-label="Permalink to &quot;3️⃣ 尿素價格 + 多單訊號（每月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>尿素價格</td><td>⚪ 暫停追蹤</td><td>本週無重大數據更新</td></tr><tr><td>費城期货信號</td><td>⚪ 暫停追蹤</td><td>同上</td></tr></tbody></table><h3 id="_4️⃣-霍爾木茲海峽通航狀態-即時" tabindex="-1">4️⃣ 霍爾木茲海峽通航狀態（即時） <a class="header-anchor" href="#_4️⃣-霍爾木茲海峽通航狀態-即時" aria-label="Permalink to &quot;4️⃣ 霍爾木茲海峽通航狀態（即時）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>通航狀況</td><td>🔴 <strong>重大變化</strong></td><td>美伊 MoU 擬定中：60 天停火 + 重新開放海峡</td></tr><tr><td>影響評估</td><td>🔴 正面利多</td><td>通航恢復 → 運輸成本下降、保險費用歸零、糧食出口路徑暢通</td></tr><tr><td>當前風險</td><td>🟡 協議未簽署</td><td>Trump 表態「不要急」，伊朗否認同意移交核原料</td></tr></tbody></table><p>📅 <strong>來源</strong>: The Guardian, CBS News, Al Jazeera (2026-05-24)</p><h3 id="_5️⃣-中美貿易-中國進口-每月" tabindex="-1">5️⃣ 中美貿易 + 中國進口（每月） <a class="header-anchor" href="#_5️⃣-中美貿易-中國進口-每月" aria-label="Permalink to &quot;5️⃣ 中美貿易 + 中國進口（每月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>中國 Soybean 進口</td><td>⚪ 資料不足</td><td>4 月數據待發布</td></tr><tr><td>中美貿易動態</td><td>🟡 穩定</td><td>無突發新聞</td></tr></tbody></table><h3 id="_6️⃣-天然氣價格-每月" tabindex="-1">6️⃣ 天然氣價格（每月） <a class="header-anchor" href="#_6️⃣-天然氣價格-每月" aria-label="Permalink to &quot;6️⃣ 天然氣價格（每月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>Henry Hub NG</td><td>🟡 下跌中</td><td>$2.98–3.00/MMBtu（5/21 結算），EIA Q2 預估值 $2.83</td></tr><tr><td>對黃豆影響</td><td>🟡 正面</td><td>低天然氣 = 低 fertilizer 成本 = 有利農民利潤</td></tr></tbody></table><p>📅 <strong>來源</strong>: EIA STEO (2026-05-20), Google Finance</p><h3 id="_7️⃣-聖嬰-拉尼娜氣候風險-每季" tabindex="-1">7️⃣ 聖嬰/拉尼娜氣候風險（每季） <a class="header-anchor" href="#_7️⃣-聖嬰-拉尼娜氣候風險-每季" aria-label="Permalink to &quot;7️⃣ 聖嬰/拉尼娜氣候風險（每季）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>ENSO 狀態</td><td>⚪ 資料未更新</td><td>需等待 NOAA 最新 CPC 展望</td></tr><tr><td>對美國種植影響</td><td>🟢 暫無重大威脅</td><td>目前種植期未顯示異常天氣</td></tr></tbody></table><h3 id="_8️⃣-cbot-大豆價格區間-每日" tabindex="-1">8️⃣ CBOT 大豆價格區間（每日） <a class="header-anchor" href="#_8️⃣-cbot-大豆價格區間-每日" aria-label="Permalink to &quot;8️⃣ CBOT 大豆價格區間（每日）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>July 2026 (ZSN6)</td><td>🔴 最新 $1,199.75</td><td>5/24 报价 1199&#39;6（+5&#39;4，+0.46% vs 前结算 1194&#39;2）</td></tr><tr><td>May 2026 (ZSK26)</td><td>❌ 已到期</td><td>5/14 到期最後報價 1215-2</td></tr><tr><td>區間判斷</td><td>🟡 中性偏強</td><td>種植進度良好壓低價格，但 MoU 帶來的運費下行也限制漲幅</td></tr></tbody></table><p>📅 <strong>來源</strong>: CME Group (2026-05-24), Barchart</p><hr><h2 id="📰-即時國際黃豆新聞-5-條" tabindex="-1">📰 即時國際黃豆新聞（5 條） <a class="header-anchor" href="#📰-即時國際黃豆新聞-5-條" aria-label="Permalink to &quot;📰 即時國際黃豆新聞（5 條）&quot;">​</a></h2><h3 id="_1-美伊-mou-可能重開霍爾木茲海峽-—-影響全球糧食運輸" tabindex="-1">1. 美伊 MoU 可能重開霍爾木茲海峽 — 影響全球糧食運輸 <a class="header-anchor" href="#_1-美伊-mou-可能重開霍爾木茲海峽-—-影響全球糧食運輸" aria-label="Permalink to &quot;1. 美伊 MoU 可能重開霍爾木茲海峽 — 影響全球糧食運輸&quot;">​</a></h3><ul><li>若 MoU 簽署，Hormuz 通航恢復 → 從巴西/阿根廷經好望角繞行的路線不再必要</li><li>運輸成本大幅下降，直接利好農產品出口競爭力</li><li><strong>預測</strong>：運費下降可能令 CBOT 大豆短線承壓 3-5%</li></ul><h3 id="_2-美國大豆種植進度超前五年平均-—-供應壓力增加" tabindex="-1">2. 美國大豆種植進度超前五年平均 — 供應壓力增加 <a class="header-anchor" href="#_2-美國大豆種植進度超前五年平均-—-供應壓力增加" aria-label="Permalink to &quot;2. 美國大豆種植進度超前五年平均 — 供應壓力增加&quot;">​</a></h3><ul><li>全國 67% 種植率 vs 五年平均高 7pts，苗情 32% vs 五年平均高 9pts</li><li>多數主要州份領先，特別是中西部和北部</li><li><strong>影響</strong>：丰收預期強化 → 壓低近月合約</li></ul><h3 id="_3-brent-油價因地緣政治降溫回跌至-99-2" tabindex="-1">3. Brent 油價因地緣政治降溫回跌至 $99.2 <a class="header-anchor" href="#_3-brent-油價因地緣政治降溫回跌至-99-2" aria-label="Permalink to &quot;3. Brent 油價因地緣政治降溫回跌至 $99.2&quot;">​</a></h3><ul><li>油價回落降低化肥生產成本（天然氣為氮肥主要原料）</li><li>同時降低農業运输與耕作燃料成本</li><li><strong>傳導鏈</strong>：低油價 → 低肥料/燃油成本 → 農民成本下降 → 支撐邊際產能</li></ul><h3 id="_4-eia-下修-2026-年天然氣價格預測至-3-50-mmbtu" tabindex="-1">4. EIA 下修 2026 年天然氣價格預測至 $3.50/MMBtu <a class="header-anchor" href="#_4-eia-下修-2026-年天然氣價格預測至-3-50-mmbtu" aria-label="Permalink to &quot;4. EIA 下修 2026 年天然氣價格預測至 $3.50/MMBtu&quot;">​</a></h3><ul><li>溫和季節需求 + 庫存充足 → 天然氣價格偏低</li><li>對氮肥成本形成結構性壓低</li><li><strong>長期意義</strong>：2026 全年 fertilizer 成本有望低於 2025</li></ul><h3 id="_5-波羅的海乾散貨指數-bdi-升至-3-092" tabindex="-1">5. 波羅的海乾散貨指數 BDI 升至 3,092 <a class="header-anchor" href="#_5-波羅的海乾散貨指數-bdi-升至-3-092" aria-label="Permalink to &quot;5. 波羅的海乾散貨指數 BDI 升至 3,092&quot;">​</a></h3><ul><li>較上月上漲 11.9%，反映貨運需求回升</li><li>但 Hormuz 封鎖期間的繞行效應仍推升運費</li><li><strong>展望</strong>：若 Hormuz 重開 → BDI 短期回落 → 運費正常化</li></ul><p>📅 <strong>來源</strong>: CME Group, DTN, EIA, Trading Economics, IndexBox.io (2026-05-24)</p><hr><h2 id="📈-情景分析" tabindex="-1">📈 情景分析 <a class="header-anchor" href="#📈-情景分析" aria-label="Permalink to &quot;📈 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>機率</th><th>CBOT Soy July 影響</th><th>傳導機制</th></tr></thead><tbody><tr><td><strong>A. MoU 簽署，Hormuz 重開</strong></td><td>45%</td><td>-$30 to -$60/Bu</td><td>運費大幅下降 + 油價跌 + 投機部位平倉</td></tr><tr><td><strong>B. MoU 談判破裂，現狀延續</strong></td><td>35%</td><td>持平 or +$20/Bu</td><td>繞行運費持續高企 + 風險溢價</td></tr><tr><td><strong>C. 部分妥協，有限度重開</strong></td><td>20%</td><td>-$10 to +$10/Bu</td><td>部分恢復但有新風險事件干擾</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>CME Group (2026-05-24): Soybean July 2026 futures quote ZSN6 @ 1199&#39;6</li><li>DTN/PF (2026-05-18): Crop progress report - corn 76% planted, soybeans 67%</li><li>Southeast AgNet (2026-05-20): Strong planting progress across major states</li><li>Benzinga (2026-05-24): Brent crude falls on US-Iran deal news</li><li>EIA STEO (2026-05-20): Natural gas forecast lowered to $3.50</li><li>Investing.com (2026-05-24): Baltic Dry Index live data @ 3,092</li><li>Axios.com (2026-05-24): US-Iran deal details and timeline</li><li>The Guardian (2026-05-24): Strait of Hormuz reopening conditions</li></ol><hr><p><strong>報告生成時間：2026-05-25 05:00 TST</strong><strong>下次追蹤：2026-05-26</strong></p>',49)])])}const _=a(o,[["render",h]]);export{c as __pageData,_ as default};
